	 * {@code OutputDirectoryProvider}.
	 *
	 * @since 6.0
	 */
	@API(status = INTERNAL, since = "6.0")
	static OutputDirectoryProvider castOrAdapt(OutputDirectoryCreator outputDirectoryCreator) {
